export const techniquesByAge = (age: string) =>
  age === 'all' ? TECHNIQUES : TECHNIQUES.filter(t => t.ageGroups.includes(age as any));

export const techniquesByCategory = (cat: string) =>
  cat === 'all' ? TECHNIQUES : TECHNIQUES.filter(t => t.category === cat);
